      { "from": "Saga Orchestrator", "to": "Payment Service", "contract": "Command: ChargeCustomer { orderId, customerId, amount } → Reply: PaymentCharged { transactionId } | PaymentFailed { reason }", "coupling_type": "async-command" },
      { "from": "Saga Orchestrator", "to": "Courier Service", "contract": "Command: AssignCourier { orderId, pickupLocation, deliveryLocation } → Reply: CourierAssigned { courierId } | CourierAssignmentFailed { reason }", "coupling_type": "async-command" },
      { "from": "Saga Orchestrator", "to": "Inventory Service", "contract": "Compensation: ReleaseItems { orderId, items[] } → Reply: ItemsReleased", "coupling_type": "async-command" },
      { "from": "Saga Orchestrator", "to": "Payment Service", "contract": "Compensation: RefundPayment { orderId, transactionId } → Reply: PaymentRefunded", "coupling_type": "async-command" },
      { "from": "Saga Orchestrator", "to": "Courier Service", "contract": "Compensation: UnassignCourier { orderId, courierId } → Reply: CourierUnassigned", "coupling_type": "async-command" }
    ],
    "data_flow": "1. Client → Order Service: CreateOrder request. 2. Saga Orchestrator drives forward: CreateOrder(PENDING) → ReserveItems → ChargeCustomer → AssignCourier. 3. Each service replies with success/failure. 4. On success at all steps: Order transitions to CONFIRMED. 5. On failure at step N: compensations fire in reverse from step N-1 down to step 1, then Order transitions to CANCELLED. 6. Saga state is persisted after each step transition to survive crashes.",
    "patterns_used": [
      { "pattern": "Orchestration-based Saga", "rationale": "Centralizes saga logic in the Order Service, making the compensation flow explicit, testable, and debuggable. Preferred over choreography here because the flow is strictly sequential with 4 steps — choreography would scatter the logic across services and make failure recovery harder to reason about." },
      { "pattern": "Compensating Transactions", "rationale": "Each forward step has a semantic inverse (reserve→release, charge→refund, assign→unassign). These are not database rollbacks — they are new business operations that undo the effect." },
      { "pattern": "Saga State Machine", "rationale": "The saga is modeled as a state machine with explicit states for each step and failure mode. This makes it crash-recoverable — on restart, the orchestrator reads persisted state and resumes or compensates." },
      { "pattern": "Idempotent Operations", "rationale": "All commands and compensations must be idempotent (keyed by orderId + step) to handle at-least-once message delivery safely." },
      { "pattern": "Outbox Pattern", "rationale": "Services write their local state change and the outbound message in a single local transaction, then a relay publishes the message. This prevents the dual-write problem (local DB commit succeeds but message publish fails)." }
